// Validate URL and extract metadata
// Handle both flat payload and n8n-wrapped payload (body key)
const rawInput = $input.first().json;
const payload = rawInput.body || rawInput;

const url = payload.url || '';
const importId = payload.importId || '';
const callbackUrl = payload.callbackUrl || '';
const callbackSecret = payload.callbackSecret || '';
let platform = payload.platform || 'blog';

if (!url || !importId || !callbackUrl) {
  throw new Error('Missing required fields: url, importId, callbackUrl');
}

if (!/^https?:\/\//i.test(url)) {
  throw new Error('Invalid URL: must start with http:// or https://');
}

const domainMatch = url.match(/^https?:\/\/(?:www\.)?([^/\s]+)/i);
const domain = domainMatch ? domainMatch[1] : '';

if (url.includes('youtube.com/watch') || url.includes('youtu.be/')) {
  platform = 'youtube';
}

let videoId = null;
let thumbnailUrl = null;
if (platform === 'youtube') {
  const ytMatch = url.match(/[?&]v=([^&#]+)/) || url.match(/youtu\.be\/([^?&#]+)/);
  videoId = ytMatch ? ytMatch[1] : null;
  if (!videoId) {
    throw new Error('Could not extract YouTube video ID from URL: ' + url);
  }
  thumbnailUrl = 'https://img.youtube.com/vi/' + videoId + '/maxresdefault.jpg';
}

return {
  json: {
    url,
    importId,
    callbackUrl,
    callbackSecret,
    platform,
    domain,
    videoId,
    thumbnailUrl
  }
};

// Format defuddle response for YouTube — strip YAML frontmatter, extract title
const body = $input.first().json.body || $input.first().json.data || '';
const prev = $('Validate URL').first().json;

// Strip YAML frontmatter
const frontmatterMatch = body.match(/^---\n([\s\S]*?)\n---\n/);
let videoTitle = 'YouTube Recipe';
if (frontmatterMatch) {
  const titleMatch = frontmatterMatch[1].match(/^title:\s*(.+)$/m);
  if (titleMatch) videoTitle = titleMatch[1].trim().replace(/^['"]|['"]$/g, '');
}

const transcriptText = body.replace(/^---\n[\s\S]*?\n---\n/, '').substring(0, 6000);

return {
  json: {
    url: prev.url,
    importId: prev.importId,
    callbackUrl: prev.callbackUrl,
    callbackSecret: prev.callbackSecret,
    videoTitle,
    transcriptText,
    sourceType: 'defuddle',
    thumbnailUrl: prev.thumbnailUrl
  }
};

// Parse ytInitialPlayerResponse from YouTube page HTML (same approach as defuddle fallback)
const html = $input.first().json.data || $input.first().json.body || '';
const prev = $('Validate URL').first().json;

if (!html || html.length < 1000) {
  return {
    json: {
      callbackUrl: prev.callbackUrl, callbackSecret: prev.callbackSecret,
      importId: prev.importId, url: prev.url, videoTitle: '',
      transcriptUrl: null, descriptionText: null, thumbnailUrl: prev.thumbnailUrl,
      error: 'Failed to fetch YouTube page (length: ' + (html || '').length + ')'
    }
  };
}

// Extract ytInitialPlayerResponse JSON from HTML script tags
let playerData = null;
const marker = 'ytInitialPlayerResponse';
const idx = html.indexOf(marker);
if (idx !== -1) {
  const startBrace = html.indexOf('{', idx);
  if (startBrace !== -1) {
    let depth = 0;
    let end = startBrace;
    for (let i = startBrace; i < html.length && i < startBrace + 500000; i++) {
      if (html[i] === '{') depth++;
      else if (html[i] === '}') { depth--; if (depth === 0) { end = i; break; } }
    }
    if (depth === 0) {
      try { playerData = JSON.parse(html.substring(startBrace, end + 1)); } catch (e) {}
    }
  }
}

if (!playerData || !playerData.videoDetails) {
  // Try to get at least the title from the HTML
  const titleMatch = html.match(/<title>([^<]+)<\/title>/);
  const pageTitle = titleMatch ? titleMatch[1].replace(' - YouTube', '').trim() : '';
  // Try to extract description from meta tag
  const descMatch = html.match(/property="og:description"\s+content="([^"]*)"/)
    || html.match(/name="description"\s+content="([^"]*)"/)
    || html.match(/"shortDescription"\s*:\s*"((?:[^"\\]|\\.)*)"/);
  const desc = descMatch ? descMatch[1].replace(/\\n/g, '\n').replace(/\\"/g, '"') : '';

  if (desc.length > 50) {
    return {
      json: {
        url: prev.url, importId: prev.importId,
        callbackUrl: prev.callbackUrl, callbackSecret: prev.callbackSecret,
        videoTitle: pageTitle || 'YouTube Recipe',
        transcriptUrl: null,
        descriptionText: desc.substring(0, 6000),
        thumbnailUrl: prev.thumbnailUrl, error: null
      }
    };
  }
  return {
    json: {
      callbackUrl: prev.callbackUrl, callbackSecret: prev.callbackSecret,
      importId: prev.importId, url: prev.url, videoTitle: pageTitle || '',
      transcriptUrl: null, descriptionText: null, thumbnailUrl: prev.thumbnailUrl,
      error: 'Could not parse ytInitialPlayerResponse from YouTube page'
    }
  };
}

const videoTitle = playerData.videoDetails.title || 'YouTube Recipe';
const description = playerData.videoDetails.shortDescription || '';

const tracks = playerData?.captions?.playerCaptionsTracklistRenderer?.captionTracks;
if (tracks && tracks.length > 0) {
  const enTrack = tracks.find(t => t.languageCode === 'en' || t.languageCode === 'en-US');
  const track = enTrack || tracks[0];
  if (track?.baseUrl) {
    return {
      json: {
        url: prev.url, importId: prev.importId,
        callbackUrl: prev.callbackUrl, callbackSecret: prev.callbackSecret,
        videoTitle, transcriptUrl: track.baseUrl,
        descriptionText: null, thumbnailUrl: prev.thumbnailUrl, error: null
      }
    };
  }
}

if (description.length > 50) {
  return {
    json: {
      url: prev.url, importId: prev.importId,
      callbackUrl: prev.callbackUrl, callbackSecret: prev.callbackSecret,
      videoTitle, transcriptUrl: null,
      descriptionText: description.substring(0, 6000),
      thumbnailUrl: prev.thumbnailUrl, error: null
    }
  };
}

return {
  json: {
    callbackUrl: prev.callbackUrl, callbackSecret: prev.callbackSecret,
    importId: prev.importId, url: prev.url, videoTitle,
    transcriptUrl: null, descriptionText: null,
    thumbnailUrl: prev.thumbnailUrl,
    error: 'No captions or description found in page data'
  }
};

// Parse transcript from XML captions or description fallback
const raw = $input.first().json;
const prev = $('Extract Transcript URL').first().json;

if (prev.error) {
  return {
    json: {
      callbackUrl: prev.callbackUrl,
      callbackSecret: prev.callbackSecret,
      importId: prev.importId,
      error: prev.error,
      rawContent: ''
    }
  };
}

if (!prev.transcriptUrl && prev.descriptionText) {
  return {
    json: {
      url: prev.url,
      importId: prev.importId,
      callbackUrl: prev.callbackUrl,
      callbackSecret: prev.callbackSecret,
      videoTitle: prev.videoTitle,
      transcriptText: prev.descriptionText,
      thumbnailUrl: prev.thumbnailUrl,
      sourceType: 'description'
    }
  };
}

// Parse XML caption response
const xml = raw.data || raw.body || (typeof raw === 'string' ? raw : '');
if (xml && xml.length > 50) {
  const segments = [];
  // Match <text start="..." dur="...">content</text> elements
  const regex = /<text[^>]*>([^<]*)<\/text>/g;
  let match;
  while ((match = regex.exec(xml)) !== null) {
    let text = match[1]
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/\n/g, ' ')
      .trim();
    if (text) segments.push(text);
  }
  if (segments.length > 0) {
    const transcriptText = segments.join(' ').substring(0, 6000);
    return {
      json: {
        url: prev.url,
        importId: prev.importId,
        callbackUrl: prev.callbackUrl,
        callbackSecret: prev.callbackSecret,
        videoTitle: prev.videoTitle,
        transcriptText,
        thumbnailUrl: prev.thumbnailUrl,
        sourceType: 'transcript'
      }
    };
  }
}

return {
  json: {
    callbackUrl: prev.callbackUrl,
    callbackSecret: prev.callbackSecret,
    importId: prev.importId,
    error: 'No transcript content found',
    rawContent: ''
  }
};

