// Format GPT response for callback
// With simplifyOutput + jsonOutput, $input.first().json IS the parsed recipe directly
const parsedRecipe = $input.first().json;

// Get prevData — could come from defuddle blog path or fallback HTML path
let prevData;
try { prevData = $('Format Defuddle Blog').first().json; } catch(e) { prevData = null; }
if (!prevData || !prevData.callbackUrl) {
  try { prevData = $('Extract JSON-LD').first().json; } catch(e) { prevData = null; }
}
if (!prevData || !prevData.callbackUrl) {
  prevData = { callbackUrl: '', callbackSecret: '', importId: '', rawText: '' };
}

if (!parsedRecipe || parsedRecipe.error) {
  return {
    json: {
      callbackUrl: prevData.callbackUrl,
      callbackSecret: prevData.callbackSecret,
      importId: prevData.importId,
      error: (parsedRecipe && parsedRecipe.error) || 'GPT returned empty response',
      rawContent: prevData.rawText || ''
    }
  };
}

// Merge imageUrl from defuddle frontmatter if GPT didn't find one
if (!parsedRecipe.imageUrl && prevData.imageUrl) {
  parsedRecipe.imageUrl = prevData.imageUrl;
}

return {
  json: {
    callbackUrl: prevData.callbackUrl,
    callbackSecret: prevData.callbackSecret,
    importId: prevData.importId,
    recipe: parsedRecipe,
    rawContent: prevData.rawText || '',
    rawMetadata: { title: parsedRecipe.title, url: prevData.url, source: 'gpt' }
  }
};

// Format JSON-LD result for callback
const data = $input.first().json;

return {
  json: {
    callbackUrl: data.callbackUrl,
    callbackSecret: data.callbackSecret,
    importId: data.importId,
    recipe: data.parsedRecipe,
    rawContent: data.rawText,
    rawMetadata: { title: data.parsedRecipe.title, url: data.url, source: 'json-ld' }
  }
};
